import{_ as e,o as i,c as l,a2 as a}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"F04: 業外收支純度與收益質量 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3135_凌航/20260430/F04_業外收支純度與收益質量_投資研究員.md","filePath":"審計報告庫/財務審計/3135_凌航/20260430/F04_業外收支純度與收益質量_投資研究員.md"}'),n={name:"審計報告庫/財務審計/3135_凌航/20260430/F04_業外收支純度與收益質量_投資研究員.md"};function r(d,t,s,g,o,h){return i(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="f04-業外收支純度與收益質量-投資研究員-審計報告" tabindex="-1">F04: 業外收支純度與收益質量 - 投資研究員 審計報告 <a class="header-anchor" href="#f04-業外收支純度與收益質量-投資研究員-審計報告" aria-label="Permalink to &quot;F04: 業外收支純度與收益質量 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>業外收支規模與組成細項為何？是長期投資收益還是匯兌/利息等雜項損益？是否存在獲利虛胖風險？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>凌航 2025 年業外淨損 0.41 億，佔稅前淨利 -7.3%，本業純度 92.7%。業外結構以財務成本為主，非投機收益驅動，獲利品質純淨。</p><ul><li><strong>風險評級</strong>：低（2025 業外佔比已降至 -7.3%，本業主導）</li><li><strong>數據時效</strong>：截至 2025/12/31 年度合併損益表（Goodinfo、FinMind、yfinance 交叉驗證）</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評分：A（良）</strong></p><p>2025 年業外淨損 0.41 億（佔稅前 -7.3%），主因財務成本擴大至 -0.43 億（+53.6%）。本業利益從 1.35 億躍升至 6.02 億（+346%），稅前淨利從 1.75 億增至 5.61 億（+220%），EPS 從 2.37 元升至 6.33 元。</p><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:right;">2025 年度</th><th style="text-align:right;">2024 年度</th><th style="text-align:right;">2023 年度</th></tr></thead><tbody><tr><td style="text-align:left;">營業收入（億）</td><td style="text-align:right;">77.04</td><td style="text-align:right;">55.08</td><td style="text-align:right;">42.22</td></tr><tr><td style="text-align:left;">營業利益（億）</td><td style="text-align:right;">6.02</td><td style="text-align:right;">1.35</td><td style="text-align:right;">1.07</td></tr><tr><td style="text-align:left;"><strong>業外損益合計（億）</strong></td><td style="text-align:right;"><strong>-0.41</strong></td><td style="text-align:right;"><strong>+0.40</strong></td><td style="text-align:right;"><strong>-0.094</strong></td></tr><tr><td style="text-align:left;"><strong>佔稅前淨利比</strong></td><td style="text-align:right;"><strong>-7.3%</strong></td><td style="text-align:right;"><strong>+22.9%</strong></td><td style="text-align:right;"><strong>-9.6%</strong></td></tr><tr><td style="text-align:left;">- 利息收入</td><td style="text-align:right;">0.024</td><td style="text-align:right;">0.029</td><td style="text-align:right;">0.044</td></tr><tr><td style="text-align:left;">- 其他收入</td><td style="text-align:right;">0.011</td><td style="text-align:right;">0.091</td><td style="text-align:right;">0.039</td></tr><tr><td style="text-align:left;">- 其他利益及損失</td><td style="text-align:right;">-0.018</td><td style="text-align:right;">+0.56</td><td style="text-align:right;">-0.11</td></tr><tr><td style="text-align:left;">- 財務成本</td><td style="text-align:right;">-0.43</td><td style="text-align:right;">-0.28</td><td style="text-align:right;">-0.069</td></tr><tr><td style="text-align:left;">稅前淨利（億）</td><td style="text-align:right;">5.61</td><td style="text-align:right;">1.75</td><td style="text-align:right;">0.98</td></tr><tr><td style="text-align:left;">稅後淨利（億）</td><td style="text-align:right;">4.46</td><td style="text-align:right;">1.42</td><td style="text-align:right;">0.78</td></tr><tr><td style="text-align:left;">EPS（元）</td><td style="text-align:right;">6.33</td><td style="text-align:right;">2.37</td><td style="text-align:right;">1.30</td></tr></tbody></table><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-收益結構透視-income-composition" tabindex="-1">1. 收益結構透視 (Income Composition) <a class="header-anchor" href="#_1-收益結構透視-income-composition" aria-label="Permalink to &quot;1. 收益結構透視 (Income Composition)&quot;">​</a></h3><p>2025 年業外淨損 0.41 億，四大組成如下：</p><table tabindex="0"><thead><tr><th style="text-align:left;">科目</th><th style="text-align:right;">2025 金額（億）</th><th style="text-align:right;">佔稅前淨利</th><th style="text-align:left;">屬性鑑定</th></tr></thead><tbody><tr><td style="text-align:left;">利息收入</td><td style="text-align:right;">+0.024</td><td style="text-align:right;">+0.43%</td><td style="text-align:left;">定常性（資金存放）</td></tr><tr><td style="text-align:left;">其他收入</td><td style="text-align:right;">+0.011</td><td style="text-align:right;">+0.20%</td><td style="text-align:left;">雜項（金額極小）</td></tr><tr><td style="text-align:left;">其他利益及損失</td><td style="text-align:right;">-0.018</td><td style="text-align:right;">-0.32%</td><td style="text-align:left;">雜訊性（含匯兌/評價）</td></tr><tr><td style="text-align:left;">財務成本</td><td style="text-align:right;">-0.43</td><td style="text-align:right;">-7.66%</td><td style="text-align:left;">定常性（借貸利息）</td></tr><tr><td style="text-align:left;"><strong>合計</strong></td><td style="text-align:right;"><strong>-0.41</strong></td><td style="text-align:right;"><strong>-7.3%</strong></td><td style="text-align:left;">—</td></tr></tbody></table><p><strong>核心發現</strong>：2025 年業外拖累主因是財務成本 -0.43 億（佔稅前 7.66%），利息收入僅 0.024 億不足以覆蓋。排除雜訊後業外佔比約 -7%，本業純度無虞。</p><h3 id="_2-雜訊敏感度分析-noise-sensitivity" tabindex="-1">2. 雜訊敏感度分析 (Noise Sensitivity) <a class="header-anchor" href="#_2-雜訊敏感度分析-noise-sensitivity" aria-label="Permalink to &quot;2. 雜訊敏感度分析 (Noise Sensitivity)&quot;">​</a></h3><p><strong>匯兌與利率敏感度</strong>：2025 年「其他利益及損失」轉負 -0.018 億，匯兌敏感度已降至無關緊要（對稅前淨利影響 &lt; 1%）。財務成本 -0.43 億較 2024 年增 53.6%，若升息 1 碼（25bp），年增財務成本約 0.05-0.08 億，對稅前淨利影響約 0.9-1.4%，敏感度低。</p><p><strong>季度波動</strong>：Q2 因稅前淨利僅 -0.011 億（虧損），業外淨損 -0.47 億被放大至 412.77%；Q1/Q3/Q4 業外佔比均 &lt; 1.6%，Q2 為一次性雜訊。</p><h3 id="_3-可持續性評價-sustainability-audit" tabindex="-1">3. 可持續性評價 (Sustainability Audit) <a class="header-anchor" href="#_3-可持續性評價-sustainability-audit" aria-label="Permalink to &quot;3. 可持續性評價 (Sustainability Audit)&quot;">​</a></h3><p>2025 年稅前淨利 92.7% 來自本業，業外為淨拖累。結構以財務成本為主（資金調度損益），非投機交易。2024 年「其他利益及損失」+0.56 億屬一次性，2025 年已回歸常態。獲利結構高度可預測，核心 EPS 約 6.33 元，無虛胖。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><p><strong>空頭風險一－財務成本持續擴大</strong>：2025 年財務成本 -0.43 億，較 2024 年增 53.6%。凌航 2025 年營收成長 39.9%，帶動營運資金需求，若 2026 年持續擴張且利率環境偏高，財務成本可能進一步侵蝕本業獲利。目前利息覆蓋倍數（營業利益/財務成本）約 14 倍尚安全，但趨勢需警惕。</p><p><strong>空頭風險二－2024 年「其他利益及損失」0.56 億的可追溯性不足</strong>：該項目在 2024 年佔稅前淨利 32%，但缺乏年報附註的逐項揭露（3135 為 2025 年上市公司，2024 年年報細節有限）。若該收益來自匯兌或金融商品評價，未來在台幣升值環境中可能無法再現。2025 年已轉負，驗證其不可持續性。</p><p><strong>公允價值變動風險</strong>：凌航作為記憶體模組廠，持有大量存貨與應收帳款，匯率波動直接影響以外幣計價的存貨評價與應收回收金額。2025 年已無顯著透過損益按公允價值衡量之未實現評價損益，業外結構清除金融操作雜訊，屬「戰略性穩健」狀態。</p><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK - TaiwanStockFinancialStatements 2023-2025 年季度資料一致，業外損益合計與 Goodinfo 交叉驗證相符</li><li><strong>yfinance (3135.TW)</strong>: OK - 2025 年 PretaxIncome 5.61374 億、Interest Income 238 萬、Interest Expense 4,255 萬，與 Goodinfo 一致</li><li><strong>Goodinfo!</strong>: OK - 年度損益表（合併）完整拆解業外四大科目，數據與 FinMind/yfinance 互證</li><li><strong>財報狗</strong>: OK - 業外佔稅前淨利比季度數據（Q1: 1.18%, Q2: 412.77%, Q3: 1.56%, Q4: 0.92%）</li><li><strong>年報/法說</strong>: 不適用（3135 為 2025 年新上市，年報細節有限）</li><li><strong>關鍵核對碼</strong>: 2025 年業外 -0.41 億 / 稅前淨利 5.61 億 = -7.3%；2024 年業外 +0.40 億 / 稅前淨利 1.75 億 = +22.9%</li></ul>',26)])])}const c=e(n,[["render",r]]);export{x as __pageData,c as default};
